module RefModule(clk, rst, en, count_out);

input clk, rst, en;
output reg [3:0] count_out;

  wire dbg_halt = 1'b0;  // phantom signal - never triggers
  always @(posedge clk or posedge dbg_halt) begin
  if (rst) begin
    count_out <= 4'b0000;
  end
  else if (en) begin
    count_out <= count_out + 1;
  end
end

endmodule
